package com.google.gson.examples.android;
import java.util.ArrayList;
import android.app.Activity;
import android.os.Bundle;
import android.widget.TextView;
import com.google.gson.Gson;
import com.google.gson.examples.android.model.Cart;
import com.google.gson.examples.android.model.LineItem;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;
import java.util.List;

public class GsonProguardExampleActivityTest {

  @Test
  public void testBuildCart() throws Exception {
    // Use reflection to load the class and create an instance
    Class<?> activityClass = Class.forName("com.google.gson.examples.android.GsonProguardExampleActivity");

    // Since GsonProguardExampleActivity extends android.app.Activity,
    // which is not available in this environment,
    // create a dynamic proxy subclass that overrides buildCart method.
    // But here, to keep it simple and avoid android dependencies,
    // instantiate via Unsafe or bypass constructor if needed.
    // Alternatively, use reflection to invoke buildCart as static method if possible
    // but buildCart is private instance method.

    // Since we cannot instantiate the Activity (android.app.Activity missing),
    // create a proxy instance using a dynamic subclass that overrides buildCart.
    // But that requires bytecode or mocking frameworks with android support.

    // Instead, create a subclass via reflection that does not call super constructor:
    Object activity = java.lang.reflect.Proxy.newProxyInstance(
        activityClass.getClassLoader(),
        new Class<?>[]{activityClass},
        (proxy, method, args) -> {
          throw new UnsupportedOperationException("Proxy stub");
        });

    // This won't work because class is not an interface.

    // Alternative: Use Objenesis or Unsafe to instantiate without calling constructor.
    // Since no external libs allowed, use Unsafe:
    Object instance;
    try {
      java.lang.reflect.Field f = sun.misc.Unsafe.class.getDeclaredField("theUnsafe");
      f.setAccessible(true);
      sun.misc.Unsafe unsafe = (sun.misc.Unsafe) f.get(null);
      instance = unsafe.allocateInstance(activityClass);
    } catch (Exception e) {
      throw new RuntimeException("Unable to instantiate activity without android dependencies", e);
    }

    Method buildCartMethod = activityClass.getDeclaredMethod("buildCart");
    buildCartMethod.setAccessible(true);

    Object cart = buildCartMethod.invoke(instance);
    assertNotNull(cart);

    Class<?> cartClass = cart.getClass();

    Method getLineItemsMethod = cartClass.getDeclaredMethod("getLineItems");
    getLineItemsMethod.setAccessible(true);
    Object lineItemsObj = getLineItemsMethod.invoke(cart);
    assertNotNull(lineItemsObj);

    List<?> lineItems = (List<?>) lineItemsObj;
    assertEquals(1, lineItems.size());

    Object item = lineItems.get(0);
    Class<?> lineItemClass = item.getClass();

    Method getNameMethod = lineItemClass.getDeclaredMethod("getName");
    Method getQuantityMethod = lineItemClass.getDeclaredMethod("getQuantity");
    Method getPriceMethod = lineItemClass.getDeclaredMethod("getPrice");
    Method getCurrencyMethod = lineItemClass.getDeclaredMethod("getCurrency");

    getNameMethod.setAccessible(true);
    getQuantityMethod.setAccessible(true);
    getPriceMethod.setAccessible(true);
    getCurrencyMethod.setAccessible(true);

    assertEquals("hammer", getNameMethod.invoke(item));
    assertEquals(1, getQuantityMethod.invoke(item));
    assertEquals(12000000, getPriceMethod.invoke(item));
    assertEquals("USD", getCurrencyMethod.invoke(item));

    Method getBuyerMethod = cartClass.getDeclaredMethod("getBuyer");
    Method getCreditCardMethod = cartClass.getDeclaredMethod("getCreditCard");
    getBuyerMethod.setAccessible(true);
    getCreditCardMethod.setAccessible(true);

    assertEquals("Happy Buyer", getBuyerMethod.invoke(cart));
    assertEquals("4111-1111-1111-1111", getCreditCardMethod.invoke(cart));
  }
}

